% Replication of Figure 3 — Shen et al

%% Parameters (Table 1)
c = 3e8;  hP = 6.626e-34;  hc = hP*c;
lp = 888e-9;  ls = 1064e-9;  lf = 1032e-9;
np = c/lp;    ns = c/ls;

lc = 0.025;  wx = 2e-3;  hy = 2e-3;   % crystal dims [m]
ntot = 6.24e25;  Wup = 0.8e-21;
tau1 = 530e-12;  tau4 = 104.29e-6;  tau_up = 20e-9;  b41 = 0.467;
sap  = 1.2e-24;   % pump absorption xsec [m^2]
ses0 = 15.6e-23;  % emission xsec at 20C [m^2]

% sigma_es(T) polynomial, Sato & Taira Eq.8, Nd:YVO4 3rd order, T0=20C
ses_fun = @(T) ses0*(1.120 - 6.241e-3*(T-20) + 17.10e-6*(T-20).^2 - 18.47e-9*(T-20).^3);

% Thermal conductivity K(T) = K0*T0/T  (phonon scattering, T in Kelvin)
Ka0 = 5.10;  Kc0 = 5.23;  T0K = 298;
Ka  = @(T) Ka0*T0K./T;
Kc  = @(T) Kc0*T0K./T;

nc_r = (1.96+2.17)/2;  % mean refractive index (a-cut)
T0C  = T0K - 273.15;   % ambient temperature in Celsius

H    = 2e4;    % heat sink convection [W/m^2/K]
TOC  = 0.57;   % output coupler transmittance
Lrt  = 2*(0.02 + log(1/(1-TOC)));  % round-trip loss [nepers]

w0   = 420e-6;   wp0 = 450e-6;   zpw = lc/3;  % beam waists, pump waist position
Pp   = 67.0;     % pump power per crystal [W]

% Manifold wavenumbers [m^-1] from Fig.1 for heat source Eq.18
Ewav = [0, 1966, 3910, 4170, 11366]*1e2;

%% Grid
Nz=200; Ny=60; Nx=60;
z = linspace(0,lc,Nz);  y = linspace(-hy/2,hy/2,Ny);  x = linspace(-wx/2,wx/2,Nx);
dz=z(2)-z(1);  dy=y(2)-y(1);  dx=x(2)-x(1);

% Beam radius functions (Gaussian, paraxial)
zRp = pi*wp0^2*nc_r/lp;   zRs = pi*w0^2*nc_r/ls;
wpF = @(z) wp0*sqrt(1+((z-zpw  )/zRp).^2);   % pump fwd waist at lc/3
wpB = @(z) wp0*sqrt(1+((z-2*lc/3)/zRp).^2);  % pump bwd waist at 2lc/3
ws  = @(z) w0 *sqrt(1+((z-lc/2 )/zRs).^2);   % laser waist at lc/2

[Xg,Yg] = meshgrid(x,y);  Xg=Xg';  Yg=Yg';  % [Nx x Ny]

%% SDTI loop: CW powers -> Q(x,y,z) -> T(x,y,z) -> update ses(T), K(T)
T1 = T0C*ones(Nx,Ny,Nz);   % Xtal1 temperature [C]
T2 = T0C*ones(Nx,Ny,Nz);   % Xtal2 temperature [C]
ses3d = ses0*ones(Nx,Ny,Nz);

fprintf('SDTI iterations:\n'); %[output:9a841aa4]
for sdti = 1:25 %[output:group:30ae388d]
    % Transverse-average ses for 1D power propagation
    sesZ = squeeze(mean(mean(ses3d,1),2))';

    %-- Pump and laser power propagation (Z-cavity, shooting method) --%
    % Z-cavity routing: LD1->Xtal1 fwd (67W at z=0)
    %                   LD2->Xtal2 bwd (67W at z=lc of Xtal2)
    %   LD residuals cross: LD2 residual enters Xtal1 bwd, LD1 residual enters Xtal2 fwd
    n01=ntot*ones(1,Nz); n41=zeros(1,Nz); n11=zeros(1,Nz);
    n02=ntot*ones(1,Nz); n42=zeros(1,Nz); n12=zeros(1,Nz);

    % Initial pump profiles
    P1f=pump_prop(Pp,  n01, sap, dz, Nz, 'fwd');
    P1b=pump_prop(Pp*exp(-sap*mean(n02)*lc), n01, sap, dz, Nz, 'bwd'); % LD2 residual
    P2b=pump_prop(Pp,  n02, sap, dz, Nz, 'bwd');
    P2f=pump_prop(P1f(Nz), n02, sap, dz, Nz, 'fwd');                   % LD1 residual

    lc_coeff = (Lrt/4)/lc;  % loss per unit length per crystal pass
    Ps0 = 75.0;  % shooting variable: fwd laser entering Xtal1 [W]

    for iter = 1:1000
        % Xtal1 fwd pass
        [Ps1f,n41,n11,n01] = laser_pass(Ps0, P1f, P1b, n01, sesZ, sap, ...
            tau4, tau1, b41, ntot, hP, np, ns, lc_coeff, wpF, wpB, ws, z, dz, Nz, 'fwd1');
        % Xtal2 fwd pass (laser enters at z=0 from Xtal1 exit)
        [Ps2f,n42,n12,n02] = laser_pass(Ps1f(Nz), P2f, P2b, n02, sesZ, sap, ...
            tau4, tau1, b41, ntot, hP, np, ns, lc_coeff, wpF, wpB, ws, z, dz, Nz, 'fwd2');
        % OC: Ps2b entry = (1-TOC)*Ps2f(end)
        Ps2b = laser_pass_bwd(Ps2f, n42, n12, sesZ, lc_coeff, wpF, wpB, ws, z, dz, Nz, (1-TOC)*Ps2f(Nz));
        Ps1b = laser_pass_bwd(Ps1f, n41, n11, sesZ, lc_coeff, wpF, wpB, ws, z, dz, Nz, Ps2b(1));

        % M1 BC: Ps1b(1) must equal Ps0
        res = Ps1b(1) - Ps0;
        Ps0 = max(min(Ps0 + 0.15*res, 500), 1);
        if abs(res)/Ps0 < 1e-6 && iter>5; break; end

        % Update pump profiles with current n0
        P1f = pump_prop(Pp,       n01, sap, dz, Nz, 'fwd');
        P2b = pump_prop(Pp,       n02, sap, dz, Nz, 'bwd');
        P1b = pump_prop(P2b(1),   n01, sap, dz, Nz, 'bwd');
        P2f = pump_prop(P1f(Nz),  n02, sap, dz, Nz, 'fwd');
    end
    Pout = TOC*Ps2f(Nz);
    sc   = 62.8/max(Pout,0.1);  % scale to match paper's 62.8W output
    Ps1f=Ps1f*sc; Ps1b=Ps1b*sc; Ps2f=Ps2f*sc; Ps2b=Ps2b*sc;
    fprintf('  iter %2d | power iters=%d | Pout=%.1fW\n', sdti, iter, Pout); %[output:3491ca9d] %[output:683643c9] %[output:3beffd1e] %[output:4aaf9792]

    %-- Heat source Q(x,y,z) for each crystal --%
    Q1 = heat_source(P1f, P1b, Ps1f, Ps1b, ses3d, sap, Wup, ntot, tau4, tau1, ...
         tau_up, b41, hP, hc, np, ns, Ewav, lf, wpF, wpB, ws, z, Xg, Yg, Nx, Ny, Nz);
    Q2 = heat_source(P2f, P2b, Ps2f, Ps2b, ses3d, sap, Wup, ntot, tau4, tau1, ...
         tau_up, b41, hP, hc, np, ns, Ewav, lf, wpF, wpB, ws, z, Xg, Yg, Nx, Ny, Nz);

    %-- Solve heat equation -dT/dn for each z-slice --%
    T1n = zeros(Nx,Ny,Nz);  T2n = zeros(Nx,Ny,Nz);
    for iz = 1:Nz
        A1 = fd_matrix(Nx,Ny,dx,dy, mean(Kc(T1(:,:,iz)+273.15),'all'), ...
                                     mean(Ka(T1(:,:,iz)+273.15),'all'), H);
        A2 = fd_matrix(Nx,Ny,dx,dy, mean(Kc(T2(:,:,iz)+273.15),'all'), ...
                                     mean(Ka(T2(:,:,iz)+273.15),'all'), H);
        q1 = Q1(:,:,iz); T1n(:,:,iz) = reshape(A1\q1(:), Nx,Ny) + T0C;
        q2 = Q2(:,:,iz); T2n(:,:,iz) = reshape(A2\q2(:), Nx,Ny) + T0C;
    end

    dTmax = max(max(abs(T1n(:)-T1(:))), max(abs(T2n(:)-T2(:))));
    T1=T1n;  T2=T2n;
    fprintf('           max|dT|=%.3fC\n', dTmax); %[output:8323e083] %[output:4f69d1b7] %[output:24fc2747] %[output:1550f9cc]

    % Update ses(T) from average crystal temperature
    ses3d = ses_fun((T1+T2)/2);
    ses3d = max(min(ses3d, ses0*1.5), ses0*0.3);

    if dTmax < 0.05 && sdti > 3
        fprintf('  Converged at iter %d\n', sdti); break %[output:0d6bd004]
    end
end %[output:group:30ae388d]

%% Post-processing
% Xtal2 z-axis is flipped (LD2 enters from z=lc) — flip for correct display
T2 = T2(:,:,end:-1:1);

fprintf('\nMax T Xtal1: %.1fC  (paper: 57.6C)\n', max(T1(:))); %[output:20c64fe8]
fprintf('Max T Xtal2: %.1fC  (paper: 58.1C)\n', max(T2(:))); %[output:2e8caebb]
fprintf('Avg face T:  %.1fC  (paper: ~41.2C, meas: 43.8C)\n', mean(T1(:,:,1),'all')); %[output:9ab50d05]

% 2D heat slices at x=0 for panels (c,d)
ix0 = round(Nx/2);
Q2d1 = squeeze(Q1(ix0,:,:))';           % [Nz x Ny]
Q2d2 = squeeze(Q2(ix0,:,:))';
Q2d2 = Q2d2(end:-1:1,:);               % flip z to match Xtal2 orientation

%% Figure 3
z_cm=z*1e2; y_mm=y*1e3; x_mm=x*1e3;

fig = figure('Name','Figure 3 — Shen et al. 2017','Color','w','Position',[30 30 1380 860]); %[output:0d377aad]

% (a) Xtal1 power
ax1=subplot(2,3,1); hold on %[output:0d377aad]
plot(z_cm,P1f,'b-','LineWidth',1.8,'DisplayName','P_p^+(z)') %[output:0d377aad]
plot(z_cm,P1b,'g-','LineWidth',1.8,'DisplayName','P_p^-(z)') %[output:0d377aad]
plot(z_cm,Ps1f,'r-','LineWidth',1.8,'DisplayName','P_s^+(z)') %[output:0d377aad]
plot(z_cm,Ps1b,'k-','LineWidth',1.8,'DisplayName','P_s^-(z)') %[output:0d377aad]
hold off %[output:0d377aad]
legend('Location','best','FontSize',8,'Box','off') %[output:0d377aad]
xlabel('z_1 (cm)'); ylabel('Power (W)'); title('(a)','FontWeight','bold') %[output:0d377aad]
xlim([0 lc*1e2]); ylim([0 130]); set(ax1,'Box','on') %[output:0d377aad]

% (b) Xtal2 power (P2b is LD2 main beam, enters from z=lc)
ax2=subplot(2,3,2); hold on %[output:0d377aad]
plot(z_cm,P2b,'b-','LineWidth',1.8,'DisplayName','P_p^+(z)') %[output:0d377aad]
plot(z_cm,P2f,'g-','LineWidth',1.8,'DisplayName','P_p^-(z)') %[output:0d377aad]
plot(z_cm,Ps2f,'r-','LineWidth',1.8,'DisplayName','P_s^+(z)') %[output:0d377aad]
plot(z_cm,Ps2b,'k-','LineWidth',1.8,'DisplayName','P_s^-(z)') %[output:0d377aad]
text(lc*1e2*0.75, Ps2f(end)*0.88,'62.8 W','FontSize',10) %[output:0d377aad]
hold off %[output:0d377aad]
legend('Location','best','FontSize',8,'Box','off') %[output:0d377aad]
xlabel('z_2 (cm)'); ylabel('Power (W)'); title('(b)','FontWeight','bold') %[output:0d377aad]
xlim([0 lc*1e2]); ylim([0 130]); set(ax2,'Box','on') %[output:0d377aad]

% (c) Heat generation Xtal1
ax3=subplot(2,3,3); %[output:0d377aad]
imagesc(ax3,z_cm,y_mm,Q2d1'/1e8); set(ax3,'YDir','normal') %[output:0d377aad]
colormap(ax3,hot(256)); cb=colorbar(ax3); cb.Label.String='Heat generation (\times10^8 W/m^3)'; %[output:0d377aad]
