% Helper: plot crystal box surfaces coloured by temperature
function plot_crystal_box(ax, T3d, z_cm, x_mm, y_mm, Nz, Nx, Ny)
    [X3,Z3]  = meshgrid(x_mm,z_cm);
    [Y3,Z3b] = meshgrid(y_mm,z_cm);
    [Xe,Ye]  = meshgrid(x_mm,y_mm);
    hold(ax,'on')
    surf(ax,Z3, X3, y_mm(1) *ones(Nz,Nx), squeeze(T3d(:,1,:))',  'EdgeColor','none')
    surf(ax,Z3, X3, y_mm(Ny)*ones(Nz,Nx), squeeze(T3d(:,Ny,:))', 'EdgeColor','none')
    surf(ax,Z3b,x_mm(1) *ones(Nz,Ny),Y3,  squeeze(T3d(1,:,:))',  'EdgeColor','none')
    surf(ax,Z3b,x_mm(Nx)*ones(Nz,Ny),Y3,  squeeze(T3d(Nx,:,:))', 'EdgeColor','none')
    surf(ax,zeros(Ny,Nx),      Xe,Ye,squeeze(T3d(:,:,1))',  'EdgeColor','none')
    surf(ax,z_cm(end)*ones(Ny,Nx),Xe,Ye,squeeze(T3d(:,:,end))','EdgeColor','none')
    hold(ax,'off')
end

