%% =========================================================================
%  LOCAL FUNCTIONS
%% =========================================================================

% Propagate pump power along crystal using Beer-Lambert
function P = pump_prop(P0, n0, sap, dz, Nz, dir)
    P = zeros(1,Nz);
    if strcmp(dir,'fwd')
        P(1)=P0;
        for i=1:Nz-1; P(i+1)=P(i)*exp(-sap*n0(i)*dz); end
    else
        P(Nz)=P0;
        for i=Nz:-1:2; P(i-1)=P(i)*exp(-sap*n0(i)*dz); end
    end
end

% Forward laser pass through one crystal, updating populations
% Returns [power_profile, n4, n1, n0]
function [Ps, n4, n1, n0] = laser_pass(Ps0, Ppf, Ppb, n0, sesZ, sap, ...
    tau4, tau1, b41, ntot, hP, np, ns, lc_coeff, wpF, wpB, ws, z, dz, Nz, xtal)
    n4=zeros(1,Nz); n1=zeros(1,Nz);
    Ps=zeros(1,Nz); Ps(1)=Ps0;
    for iz=1:Nz
        s=sesZ(iz); ww=ws(z(iz));
        if strcmp(xtal,'fwd1')
            Ip=(Ppf(iz)/(pi*(wpF(z(iz))^2+ww^2)/2) + Ppb(iz)/(pi*(wpB(z(iz))^2+ww^2)/2));
        else  % Xtal2: pump roles swapped
            Ip=(Ppf(iz)/(pi*(wpF(z(iz))^2+ww^2)/2) + Ppb(iz)/(pi*(wpB(z(iz))^2+ww^2)/2));
        end
        Rp = sap*Ip/(hP*np);
        Is = (Ps(iz) + Ps0*0.9)/(pi*ww^2);
        Ws = s*Is/(hP*ns);
        den = Rp+(1/tau4+Ws)*(1+tau1*(b41/tau4+Ws));
        n4(iz)=ntot*Rp/max(den,1e-30);
        n1(iz)=tau1*(b41/tau4+Ws)*n4(iz);
        n0(iz)=max(ntot-n4(iz)-n1(iz),0);
        if iz<Nz
            Ps(iz+1)=Ps(iz)*exp((s*(n4(iz)-n1(iz))-lc_coeff)*dz);
        end
    end
end

% Backward laser pass (populations already computed from forward pass)
function Psb = laser_pass_bwd(Psf, n4, n1, sesZ, lc_coeff, wpF, wpB, ws, z, dz, Nz, Pentry)
    Psb=zeros(1,Nz); Psb(Nz)=Pentry;
    gnet = sesZ.*(n4-n1) - lc_coeff;
    for iz=Nz:-1:2; Psb(iz-1)=Psb(iz)*exp(gnet(iz)*dz); end
end

% Compute 3D heat source Q(x,y,z) [W/m^3] via Eq.18
function Q = heat_source(Ppf, Ppb, Psf, Psb, ses3d, sap, Wup, ntot, tau4, tau1, ...
    tau_up, b41, hP, hc, np, ns, Ewav, lf, wpF, wpB, ws, z, Xg, Yg, Nx, Ny, Nz)
    Q=zeros(Nx,Ny,Nz);
    for iz=1:Nz
        wf=wpF(z(iz)); wb=wpB(z(iz)); wl=ws(z(iz));
        r2=Xg.^2+Yg.^2;
        Ip=(2*Ppf(iz)/(pi*wf^2))*exp(-2*r2/wf^2) + (2*Ppb(iz)/(pi*wb^2))*exp(-2*r2/wb^2);
        Is=(2*Psf(iz)/(pi*wl^2) + 2*Psb(iz)/(pi*wl^2))*exp(-2*r2/wl^2);
        Rp=sap*Ip/(hP*np);
        for ix=1:Nx; for iy=1:Ny
            s=ses3d(ix,iy,iz);
            Ws=s*Is(ix,iy)/(hP*ns);
            Rp_=Rp(ix,iy);
            den=Rp_+(1/tau4+Ws)*(1+tau1*(b41/tau4+Ws));
            n4=ntot*Rp_/max(den,1e-30);
            n1=tau1*(b41/tau4+Ws)*n4;
            nup=Wup*n4^2*tau_up;
            Q(ix,iy,iz)=hc*(Ewav(2)-Ewav(1))*n1/tau1 ...
                       +hc*(Ewav(5)-Ewav(2))*nup/tau_up ...
                       +hc*(Ewav(5)-1/lf)*n4/tau4;
        end; end
    end
end

% Build 2D finite-difference matrix for heat eq. with Robin BCs (Eq.19-25)
% Robin BC: K*dT/dn + H*(T-T0)=0 on lateral faces; adiabatic on end faces
function A = fd_matrix(Nx, Ny, dx, dy, Kx, Ky, H)
    N=Nx*Ny; II=zeros(6*N,1); JJ=II; VV=II; nc=0;
    for iy=1:Ny; for ix=1:Nx
        k=(iy-1)*Nx+ix; dv=0;
        xL=(ix==1); xR=(ix==Nx); yB=(iy==1); yT=(iy==Ny);
        if xL
            dv=dv+Kx/dx+H;
            if ~xR; nc=nc+1; II(nc)=k; JJ(nc)=(iy-1)*Nx+ix+1; VV(nc)=-Kx/dx; end
        elseif xR
            dv=dv+Kx/dx+H;
            nc=nc+1; II(nc)=k; JJ(nc)=(iy-1)*Nx+ix-1; VV(nc)=-Kx/dx;
        else
            dv=dv+2*Kx/dx^2;
            nc=nc+1; II(nc)=k; JJ(nc)=(iy-1)*Nx+ix-1; VV(nc)=-Kx/dx^2;
            nc=nc+1; II(nc)=k; JJ(nc)=(iy-1)*Nx+ix+1; VV(nc)=-Kx/dx^2;
        end
        if yB
            dv=dv+Ky/dy+H;
            if ~yT; nc=nc+1; II(nc)=k; JJ(nc)=iy*Nx+ix; VV(nc)=-Ky/dy; end
        elseif yT
            dv=dv+Ky/dy+H;
            nc=nc+1; II(nc)=k; JJ(nc)=(iy-2)*Nx+ix; VV(nc)=-Ky/dy;
        else
            dv=dv+2*Ky/dy^2;
            nc=nc+1; II(nc)=k; JJ(nc)=(iy-2)*Nx+ix; VV(nc)=-Ky/dy^2;
            nc=nc+1; II(nc)=k; JJ(nc)=iy*Nx+ix;     VV(nc)=-Ky/dy^2;
        end
        nc=nc+1; II(nc)=k; JJ(nc)=k; VV(nc)=dv;
    end; end
    A=sparse(II(1:nc),JJ(1:nc),VV(1:nc),N,N);
end

